const query = $('接收儀表板查詢').first().json.query || {};
const period = ['7d', '30d', '90d'].includes(query.period) ? query.period : '7d';
const days = period === '90d' ? 90 : (period === '30d' ? 30 : 7);
const items = $input.all();
const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const rangeStart = new Date(today);
rangeStart.setDate(today.getDate() - days + 1);
const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);

function getString(prop) {
  if (!prop) return '';
  if (prop.type === 'title') return (prop.title || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'date') return prop.date?.start || '';
  if (prop.type === 'created_time') return prop.created_time || '';
  if (prop.type === 'last_edited_time') return prop.last_edited_time || '';
  if (prop.type === 'checkbox') return prop.checkbox || false;
  return '';
}

function asDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d;
}

function startOfDay(date) {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate());
}

function dateKey(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

function dateLabel(date) {
  return `${String(date.getMonth() + 1).padStart(2, '0')}/${String(date.getDate()).padStart(2, '0')}`;
}

function clampToRange(date) {
  const d = startOfDay(date);
  if (d < rangeStart) return new Date(rangeStart);
  if (d > today) return new Date(today);
  return d;
}

function normalizeCase(item, index) {
  const props = item.json.properties || {};
  return {
    id: item.json.id,
    index,
    caseId: getString(props['案件編號']),
    title: getString(props['案件標題']),
    type: getString(props['案件類型']) || '未分類',
    area: getString(props['案件區域']) || '未填寫',
    status: getString(props['案件狀態']) || '未設定',
    sortOrder: Number(getString(props['顯示排序']) || index + 1),
    createdAt: asDate(getString(props['建立時間']) || item.json.created_time),
    closedAt: asDate(getString(props['結案日期']))
  };
}

const cases = items.map(normalizeCase).filter(item => item.createdAt);
const todayKey = dateKey(today);
const sameDayImportedCount = cases.filter(c => dateKey(startOfDay(c.createdAt)) === todayKey).length;
const useDemoSpread = cases.length >= 10 && sameDayImportedCount / cases.length >= 0.7;

function trendCreatedDay(c) {
  if (!useDemoSpread) return startOfDay(c.createdAt);

  if (c.closedAt) {
    const d = startOfDay(c.closedAt);
    d.setDate(d.getDate() - ((c.sortOrder % 4) + 1));
    return clampToRange(d);
  }

  const d = new Date(today);
  d.setDate(today.getDate() - (c.sortOrder % days));
  return clampToRange(d);
}

function trendClosedDay(c) {
  if (!c.closedAt) return null;
  return clampToRange(c.closedAt);
}

const chartMap = new Map();
for (let i = 0; i < days; i++) {
  const d = new Date(rangeStart);
  d.setDate(rangeStart.getDate() + i);
  chartMap.set(dateKey(d), { label: dateLabel(d), newCount: 0, closedCount: 0 });
}

const monthStats = { newCount: 0, closedCount: 0, progressCount: 0 };
const typeCounts = {};
const areaCounts = {};
const statusCounts = {};

for (const c of cases) {
  const createdDay = trendCreatedDay(c);
  const createdKey = dateKey(createdDay);
  if (chartMap.has(createdKey)) chartMap.get(createdKey).newCount += 1;
  if (startOfDay(c.createdAt) >= monthStart) monthStats.newCount += 1;

  const closedDay = trendClosedDay(c);
  if (closedDay) {
    const closedKey = dateKey(closedDay);
    if (chartMap.has(closedKey)) chartMap.get(closedKey).closedCount += 1;
    if (closedDay >= monthStart) monthStats.closedCount += 1;
  }

  if (c.status !== '已結案') monthStats.progressCount += 1;
  typeCounts[c.type] = (typeCounts[c.type] || 0) + 1;
  areaCounts[c.area] = (areaCounts[c.area] || 0) + 1;
  statusCounts[c.status] = (statusCounts[c.status] || 0) + 1;
}

const chart = Array.from(chartMap.values());

return [{
  json: {
    success: true,
    period,
    days,
    total: cases.length,
    chart,
    monthStats,
    typeCounts,
    areaCounts,
    statusCounts,
    trendMode: useDemoSpread ? 'demo_spread' : 'created_time',
    updatedAt: new Date().toISOString()
  }
}];
